// Closed admin permission catalog for insurance-claim-demo.
// Synthesized from each JTBD's permissions in the bundle (W0 catalog).
// Generated by flowforge JTBD generator — do not edit by hand.

export const ADMIN_PERMISSIONS = [
	"admin.claim_intake.compensate",
	"admin.claim_intake.grant",
	"admin.claim_intake.outbox.retry",
	"admin.claim_intake.read",
] as const;

export type AdminPermission = (typeof ADMIN_PERMISSIONS)[number];

/** JTBD-keyed permission tuples; useful for per-page guards. */
export const ADMIN_PERMISSIONS_BY_JTBD = {
	"claim_intake": [
		"admin.claim_intake.compensate",
		"admin.claim_intake.grant",
		"admin.claim_intake.outbox.retry",
		"admin.claim_intake.read",
	] as const,
} as const;

export type AdminJtbdId = keyof typeof ADMIN_PERMISSIONS_BY_JTBD;

export function hasAnyAdminPermission(
	granted: ReadonlyArray<string>,
): boolean {
	return granted.some((g) => (ADMIN_PERMISSIONS as ReadonlyArray<string>).includes(g));
}

export function isAdminPermission(value: string): value is AdminPermission {
	return (ADMIN_PERMISSIONS as ReadonlyArray<string>).includes(value);
}
